<?php require_once __DIR__.'/../config/db.php';require_once __DIR__.'/../includes/csrf.php';$st=$pdo->prepare('SELECT * FROM cities WHERE slug=:s LIMIT 1');$st->execute(['s'=>trim($_GET['slug']??'')]);$city=$st->fetch();if(!$city){http_response_code(404);exit('Ville introuvable.');}$cars=$pdo->prepare('SELECT * FROM cars WHERE status != :h ORDER BY price_per_day ASC LIMIT 3');$cars->execute(['h'=>'hidden']);$popular=$cars->fetchAll();$title=$city['seo_title'];$description=$city['seo_description'];include __DIR__.'/../includes/header.php';?><section class="page-hero"><p class="eyebrow">Location voiture Maroc</p><h1><?=e($city['h1'])?></h1><p><?=nl2br(e($city['intro_text']))?></p><a class="btn primary" href="/cars/?city=<?=e($city['slug'])?>">Voir les voitures à <?=e($city['name'])?></a></section><section class="section"><h2>Points de prise en charge</h2><div class="trust-grid"><?php foreach(explode(',',$city['pickup_points']) as $p):?><span><?=e(trim($p))?></span><?php endforeach;?></div></section><section class="section"><h2>Voitures populaires</h2><div class="car-grid"><?php foreach($popular as $car) include __DIR__.'/../partials_car_card.php';?></div></section><?php include __DIR__.'/../includes/footer.php';?>